#!/usr/bin/env node
/**
 * Generate public/_redirects for Netlify / Cloudflare Pages hosting.
 *
 * Mirrors the client-side 301 logic in src/App.tsx (BouquetSlugResolver,
 * ShopifyProductRedirect, etc.) so that bots and direct visitors get a real
 * HTTP 301 instead of a JS-side redirect.
 *
 * Source of truth: src/lib/bouquetSlugs.ts (BOUQUET_SLUGS).
 *
 * NOTE: Lovable hosting ignores _redirects. This file is generated for
 * portability when the site is deployed to Netlify or Cloudflare Pages.
 * The SPA fallback at the bottom is harmless on Lovable.
 */

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const SLUGS_FILE = resolve(ROOT, "src/lib/bouquetSlugs.ts");
const OUT_FILE = resolve(ROOT, "public/_redirects");

// Parse BOUQUET_SLUGS object from the TS source without importing TS at runtime.
// Lines look like:  "handle": { slug: "x", slugEs: "y" },
const src = readFileSync(SLUGS_FILE, "utf8");
const entryRe = /"([a-z0-9-]+)":\s*\{\s*slug:\s*"([a-z0-9-]+)",\s*slugEs:\s*"([a-z0-9-]+)"\s*\}/g;

const entries = [];
let m;
while ((m = entryRe.exec(src)) !== null) {
  const [, handle, slug, slugEs] = m;
  entries.push({ handle, slug, slugEs });
}
if (entries.length === 0) {
  console.error("[generate-redirects] No entries parsed from BOUQUET_SLUGS — aborting.");
  process.exit(1);
}

const lines = [];
lines.push("# AUTO-GENERATED by scripts/generate-redirects.mjs — do not edit by hand.");
lines.push("# Regenerate with: npm run redirects   (runs as part of `npm run build`).");
lines.push("# Source: src/lib/bouquetSlugs.ts");
lines.push("");
lines.push("# --- Bouquet legacy URL → clean SEO slug (301) ---");

for (const { handle, slug, slugEs } of entries) {
  // Shopify-style URLs from Meta/Instagram ads.
  lines.push(`/products/${handle}            /bouquets/${slug}            301`);
  lines.push(`/es/products/${handle}         /es/bouquets/${slugEs}       301`);

  // Legacy two-segment fichas: /bouquets/all/<handle>, /bouquets/single-color/<handle>, etc.
  // Match any :type segment with a splat-style rule per handle.
  lines.push(`/bouquets/all/${handle}        /bouquets/${slug}            301`);
  lines.push(`/es/bouquets/all/${handle}     /es/bouquets/${slugEs}       301`);

  // Raw handle at the clean route (only redirect when handle !== slug, otherwise it's already canonical).
  if (handle !== slug) {
    lines.push(`/bouquets/${handle}          /bouquets/${slug}            301`);
  }
  if (handle !== slugEs) {
    lines.push(`/es/bouquets/${handle}       /es/bouquets/${slugEs}       301`);
  }
}

lines.push("");
lines.push("# --- Normalize trailing slash → strip it (avoid duplicate content) ---");
lines.push("# /pagina/  ->  /pagina  (301). Evita que Google indexe la misma página dos veces.");
lines.push("/*/           /:splat           301!");
lines.push("");
lines.push("# --- SPA fallback (must be last) ---");
lines.push("/*    /index.html   200");
lines.push("");

mkdirSync(dirname(OUT_FILE), { recursive: true });
writeFileSync(OUT_FILE, lines.join("\n"), "utf8");

console.log(`[generate-redirects] Wrote ${OUT_FILE} (${entries.length} handles, ${lines.length} lines).`);